import{_ as i}from"./chunks/theme.3kx3-zVK.js";import{_ as r,o as s,c as n,ag as a,j as l,E as o}from"./chunks/framework.CbQjVMS6.js";const c="/assets/screenshot2.BRvr9Qd6.jpg",p="/assets/console.5rIYX6Bq.jpg",k=JSON.parse('{"title":"What is TI Basic Powerpack?","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"what-is-powerpack.md","filePath":"what-is-powerpack.md","lastUpdated":1774323326000}'),d={name:"what-is-powerpack.md"},u={style:{"xpadding-bottom":"16px"}};function m(h,e,f,g,w,_){const t=i;return s(),n("div",null,[e[0]||(e[0]=a('<h1 id="what-is-ti-basic-powerpack" tabindex="-1">What is TI Basic Powerpack? <a class="header-anchor" href="#what-is-ti-basic-powerpack" aria-label="Permalink to &quot;What is TI Basic Powerpack?&quot;">​</a></h1><p><strong>Powerpack</strong> is a Windows program that assists with writing TI-Basic 8XP programs for Texas TI-83 or TI-84 Plus calculators — compiling and compressing them to provide new features, trim file size, and make coding a more enjoyable experience.</p><p>You will want to get familiar with the basics of <a href="http://tibasicdev.wikidot.com/starter-kit" target="_blank" rel="noreferrer">TI Basic</a> before diving into Powerpack as it’s designed for more advanced users.</p><p>Write your TI Basic code in <a href="https://education.ti.com/en/products/computer-software/ti-connect-ce-sw" target="_blank" rel="noreferrer">TI Connect CE</a> (or your favourite code editor), run <code>Powerpack.exe</code>, and have the resulting file ready for loading onto your calculator or emulator:</p><p><img src="'+c+'" alt=""></p><p><img src="'+p+'" alt=""></p><h2 id="making-ti-basic-more-enjoyable" tabindex="-1">Making TI Basic more enjoyable <a class="header-anchor" href="#making-ti-basic-more-enjoyable" aria-label="Permalink to &quot;Making TI Basic more enjoyable&quot;">​</a></h2><p>The main goal is to make TI Basic programming more enjoyable by:</p><ul><li>Letting you use unlimited comments (without increasing file size)</li><li>Letting you add blank line returns and indent your code (without increasing file size)</li><li>Allow you to give variables and “Goto” labels more descriptive names - more than just 1 or 2 characters</li><li>Automatically transferring your program to WabbitEmu and running it, every time you save the file — allowing you to test and iterate faster</li><li>Store a copy of your code in text format, for better tracking of history with git</li><li>Keeping your program file size as small as possible</li></ul><hr style="margin-bottom:32px;">',10)),l("p",u,[o(t,{size:"big",text:"Download",href:"/download"}),o(t,{size:"big",text:"Get Started",href:"/getting-started"})]),e[1]||(e[1]=a('<h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>When you run <code>Powerpack.exe</code>, here’s what it does:</p><ol><li><p>It <a href="/features/decompile-8xp">decompiles</a> your 8XP code, either when you run it on a specific file, or by watching for changes in a specific folder</p></li><li><p>Saves a copy of the original source code in plain text format (useful for version control)</p></li><li><p>Converts any Powerpack-specific syntax into standard TI-Basic syntax which your calculator understands</p></li><li><p><a href="/features/ti-basic-optimization">Optimizes</a> the program by removing comments, unnecessary characters, spaces and line returns</p></li><li><p>Saves a copy of this optimized program in text format (again, useful for version control)</p></li><li><p><a href="/features/compile-to-8xp">Recompiles</a> into 8XP format</p></li><li><p><a href="/features/autorun">Auto-run</a>: If WabbitEmu is detected, it will attempt to load the 8XP into the emulator and press the <kbd>ENTER</kbd> key in the emulator to re-run it.</p></li><li><p>Generates a report on the file size, including the number of bytes used on each line of the file</p></li></ol><p>The resulting 8XP file is also ready for loading onto your calculator.</p>',4))])}const T=r(d,[["render",m]]);export{k as __pageData,T as default};
